import numpy as np

def dropout(x, p, training):
    if not training:
        return x                       # eval: identity
    mask = (np.random.rand(*x.shape) > p)
    return x * mask / (1.0 - p)        # zero + rescale

def batchnorm(x, gamma, beta, eps=1e-5):
    mu = x.mean(axis=0)
    var = x.var(axis=0)
    x_hat = (x - mu) / np.sqrt(var + eps)
    return gamma * x_hat + beta        # learned rescale

