def encode(word, merges):
    tokens = list(word)
    for a, b in merges:            # merges in learned order
        i = 0
        while i < len(tokens) - 1:
            if tokens[i] == a and tokens[i+1] == b:
                tokens[i:i+2] = [a + b]   # apply the merge
            else:
                i += 1
    return tokens

