def run(task, supervisor, workers, max_turns=8):
    state = {"task": task, "history": [], "done": False}
    for _ in range(max_turns):
        decision = supervisor(state)        # who next + why
        if decision["action"] == "finish":
            return decision["answer"]
        name = decision["delegate_to"]
        result = workers[name](state)       # run that agent
        state["history"].append({name: result})
    return "stopped: max turns reached"

