class Msg:
    sender: str        # which agent / supervisor
    content: str       # the payload

@dataclass
class State:
    task: str
    history: list = field(default_factory=list)  # list[Msg]
    draft: str = ""
    facts: str = ""

def supervisor(state: State) -> str:
    # Decide the next role from what's been done.
    if not state.facts:
        return "researcher"
    if not state.draft:
        return "writer"
    if "OK" not in state.history[-1].content:
        return "critic"      # still needs review
    return "finish"

def run(task: str, max_turns: int = 6) -> str:
    s = State(task=task)
    for _ in range(max_turns):
        nxt = supervisor(s)
        if nxt == "finish":
            return s.draft
        if nxt == "researcher":
            s.facts = agent(RESEARCHER, s.task)
        elif nxt == "writer":
            s.draft = agent(WRITER, s.facts)
        else:  # critic
            review = agent(CRITIC, s.draft)
            s.history.append(Msg("critic", review))
            if "OK" not in review:
                s.draft = agent(WRITER, s.facts + "\nFix: " + review)
    return s.draft

def safe_run(task, max_turns=6, deadline=60):
    start = time.time()
    s = State(task=task)
    for i in range(max_turns):
        if time.time() - start > deadline:
            return "timeout: team gave up"
        nxt = supervisor(s)
        print(f"turn {i}: -> {nxt}")     # log every handoff
        if nxt == "finish":
            return s.draft
        # ... run agent, update state ...
    return "stopped: max turns reached"

def safe_team(task, agents, max_turns=8, deadline=60):
    start, state = time.time(), {"task": task, "log": []}
    for i in range(max_turns):
        if time.time() - start > deadline:
            return "timeout: team gave up"
        nxt = route(state)               # explicit termination
        state["log"].append((i, nxt))    # observability
        if nxt == "done":
            return state.get("answer")
        try:
            run_agent(agents[nxt], state)  # scoped context inside
        except Exception as e:
            state["log"].append(("error", nxt, str(e)))
    return "stopped: max turns reached"

