import time, random
from openai import RateLimitError, APITimeoutError

def safe(fn, tries=4):
    for i in range(tries):
        try:
            return fn()
        except (RateLimitError, APITimeoutError):
            if i == tries - 1:
                raise
            time.sleep(2 ** i + random.random())  # backoff + jitter

